qry:select.qry:xquery:
					for $r in sql('
maxsize 1001
SELECT 
T.oi_sector, 
P.c_departamento, 
P.d_departamento, 
T.c_sector, 
T.d_sector
FROM 
ORG51_DEPARTAMENTOS as P,
ORG51_SECTORES as T                     
JOIN
P.oi_departamento INNER T.oi_departamento      
WHERE
P.oi_empresa={#SOURCE:@empresa}
{%?(#SOURCE:@search1!='') {% AND ( contain(ucase(P.c_departamento), {upper-case(#SOURCE:@search1)}) or contain(ucase(P.d_departamento), {upper-case(#SOURCE:@search1)}) OR contain(ucase(T.c_sector), {upper-case(#SOURCE:@search1)}) or contain(ucase(T.d_sector), {upper-case(#SOURCE:@search1)}) %} {% %} %} 
{%?(#SOURCE:@search2!='') {% OR contain(ucase(P.c_departamento), {upper-case(#SOURCE:@search2)}) or contain(ucase(P.d_departamento), {upper-case(#SOURCE:@search2)}) OR contain(ucase(T.c_sector), {upper-case(#SOURCE:@search2)}) or contain(ucase(T.d_sector), {upper-case(#SOURCE:@search2)}) %} {% %} %} 
{%?(#SOURCE:@search3!='') {% OR contain(ucase(P.c_departamento), {upper-case(#SOURCE:@search3)}) or contain(ucase(P.d_departamento), {upper-case(#SOURCE:@search3)}) OR contain(ucase(T.c_sector), {upper-case(#SOURCE:@search3)}) or contain(ucase(T.d_sector), {upper-case(#SOURCE:@search3)}) %} {% %} %}
{%?(#SOURCE:@search4!='') {% OR contain(ucase(P.c_departamento), {upper-case(#SOURCE:@search4)}) or contain(ucase(P.d_departamento), {upper-case(#SOURCE:@search4)}) OR contain(ucase(T.c_sector), {upper-case(#SOURCE:@search4)}) or contain(ucase(T.d_sector), {upper-case(#SOURCE:@search4)}) %} {% %} %} 
{%?(#SOURCE:@search5!='') {% OR contain(ucase(P.c_departamento), {upper-case(#SOURCE:@search5)}) or contain(ucase(P.d_departamento), {upper-case(#SOURCE:@search5)}) OR contain(ucase(T.c_sector), {upper-case(#SOURCE:@search5)}) or contain(ucase(T.d_sector), {upper-case(#SOURCE:@search5)}) %} {% %} %} 
{%?(#SOURCE:@search1!='') {% ) %} {% %} %} 
')/ROWS/ROW
